example.code:
# Step 1: Define abstraction
class PaymentProcessor(Protocol):
    def process(self, amount: Decimal) -> PaymentResult: ...

# Step 2: Old impl still active
class LegacyPaymentProcessor:
    def process(self, amount): return self.old_gateway.charge(amount)

# Step 3: New impl behind flag
class StripePaymentProcessor:
    def process(self, amount): return self.stripe.create_charge(amount)

def get_processor() -> PaymentProcessor:
    if feature_flags.is_enabled("stripe_payments"):
        return StripePaymentProcessor()
    return LegacyPaymentProcessor()

# Step 5: After 100% rollout, delete LegacyPaymentProcessor and the flag

async def process_order(order: Order):
    result = await current_processor.process(order)
    if feature_flags.is_enabled("dark_new_processor"):
        try:
            new_result = await new_processor.process(order)
            if result != new_result:
                logger.warning("dark launch mismatch", extra={"old": result, "new": new_result})
        except Exception as e:
            logger.error("dark launch error", exc_info=e)
    return result  # always return current result
